import anthropic
import json
from datetime import datetime, timezone

client = anthropic.Anthropic()

SCHEDULE_MEETING_TOOL = {
    "name": "schedule_meeting",
    "description": (
        "Schedule a meeting on the user's calendar. Confirm all details with the "
        "user before calling this tool. Do not call it speculatively."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "title": {
                "type": "string",
                "description": "Meeting title shown on the calendar invite.",
                "maxLength": 100,
            },
            "start_time": {
                "type": "string",
                "format": "date-time",
                "description": "Meeting start time in ISO 8601 format with timezone offset, e.g. 2025-03-15T14:00:00-07:00.",
            },
            "duration_minutes": {
                "type": "integer",
                "description": "Meeting duration in minutes.",
                "minimum": 15,
                "maximum": 480,
            },
            "meeting_type": {
                "type": "string",
                "enum": ["in-person", "video", "phone"],
                "description": "How the meeting will be held. Use 'video' for Zoom/Meet links.",
            },
            "attendees": {
                "type": "array",
                "description": "List of attendees. At least one is required.",
                "minItems": 1,
                "maxItems": 20,
                "items": {
                    "type": "object",
                    "properties": {
                        "email": {"type": "string", "format": "email"},
                        "optional": {
                            "type": "boolean",
                            "description": "True if this attendee's presence is optional.",
                        },
                    },
                    "required": ["email"],
                },
            },
            "description": {
                "type": "string",
                "description": "Optional agenda or notes for the meeting body.",
                "maxLength": 2000,
            },
        },
        "required": ["title", "start_time", "duration_minutes", "meeting_type", "attendees"],
    },
}


def schedule_meeting(**kwargs) -> dict:
    """Simulated calendar API call."""
    return {
        "event_id": "evt_7a92b",
        "calendar_link": "https://calendar.example.com/evt_7a92b",
        "status": "confirmed",
    }


def run(user_message: str) -> None:
    messages = [{"role": "user", "content": user_message}]
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        tools=[SCHEDULE_MEETING_TOOL],
        messages=messages,
    )

    if response.stop_reason == "tool_use":
        for block in response.content:
            if block.type == "tool_use":
                print(f"Calling {block.name} with:")
                print(json.dumps(block.input, indent=2))
                result = schedule_meeting(**block.input)
                # Continue conversation with tool result
                messages.append({"role": "assistant", "content": response.content})
                messages.append({"role": "user", "content": [
                    {"type": "tool_result", "tool_use_id": block.id,
                     "content": json.dumps(result)}
                ]})
                final = client.messages.create(
                    model="claude-opus-4-5",
                    max_tokens=256,
                    tools=[SCHEDULE_MEETING_TOOL],
                    messages=messages,
                )
                print(next(b.text for b in final.content if hasattr(b, "text")))
    else:
        print(next(b.text for b in response.content if hasattr(b, "text")))


run(
    "Schedule a 45-minute video call with alice@example.com and bob@example.com "
    "tomorrow at 2pm Pacific for our Q3 planning discussion."
)
